#include <stdio.h>
#include <stdlib.h>

typedef struct { long long pos; int idx; } Item;

int cmpDesc(const void *a, const void *b) {
    const Item *x = (const Item*)a;
    const Item *y = (const Item*)b;
    if (x->pos != y->pos) return (x->pos > y->pos) ? -1 : 1; // descending position
    return (x->idx < y->idx) ? -1 : 1; // ascending index for ties
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *v = (long long*)malloc(N * sizeof(long long));
        long long *x = (long long*)malloc(N * sizeof(long long));
        for (int i=0;i<N;i++) scanf("%lld %lld", &v[i], &x[i]);
        int Q; scanf("%d", &Q);
        while (Q--) {
            long long t; int k; scanf("%lld %d", &t, &k);
            Item *arr = (Item*)malloc(N * sizeof(Item));
            for (int i=0;i<N;i++) {
                arr[i].pos = x[i] + v[i] * t;
                arr[i].idx = i + 1; // 1‑based index
            }
            qsort(arr, N, sizeof(Item), cmpDesc);
            printf("%d\n", arr[k-1].idx);
            free(arr);
        }
        free(v); free(x);
    }
    return 0;
}

