import java.io.*;
import java.util.*;

public class Main {
    private static final class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] v = new long[N];
            long[] x = new long[N];
            for (int i = 0; i < N; i++) {
                v[i] = fs.nextLong();
                x[i] = fs.nextLong();
            }
            int Q = fs.nextInt();
            while (Q-- > 0) {
                long t = fs.nextLong();
                int k = fs.nextInt();
                long[][] arr = new long[N][2]; // [pos, idx]
                for (int i = 0; i < N; i++) {
                    arr[i][0] = x[i] + v[i] * t;
                    arr[i][1] = i + 1;
                }
                Arrays.sort(arr, (a, b) -> {
                    if (a[0] != b[0]) return Long.compare(b[0], a[0]); // descending position
                    return Long.compare(a[1], b[1]); // ascending index
                });
                out.append(arr[k-1][1]).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

